// apps/web/app/api/auth/[...nextauth]/route.ts
import NextAuth from "next-auth";
import AzureADProvider from "next-auth/providers/azure-ad";
import CredentialsProvider from "next-auth/providers/credentials";
import type { NextAuthOptions } from "next-auth";

const hasAzure =
  !!process.env.AZURE_AD_CLIENT_ID &&
  !!process.env.AZURE_AD_CLIENT_SECRET &&
  !!process.env.AZURE_AD_TENANT_ID;

export const authOptions: NextAuthOptions = {
  providers: hasAzure
    ? [
        AzureADProvider({
          clientId: process.env.AZURE_AD_CLIENT_ID!,
          clientSecret: process.env.AZURE_AD_CLIENT_SECRET!,
          tenantId: process.env.AZURE_AD_TENANT_ID!, // 'common' หรือ tenant GUID
        }),
      ]
    : [
        CredentialsProvider({
          name: "Mock",
          credentials: {
            email: { label: "Email", type: "email" },
          },
          async authorize(credentials) {
            // MOCK: อนุญาตทั้งหมดที่มี email
            const email = credentials?.email as string | undefined;
            if (!email) return null;
            return { id: "mock-" + Date.now(), name: email, email };
          },
        }),
      ],
  session: { strategy: "jwt" },
  pages: {
    signIn: "/login", // กำหนดหน้า login ของเราเอง
  },
  callbacks: {
    async jwt({ token, user }) {
      if (user) {
        token.email = user.email;
        token.name = user.name;
      }
      return token;
    },
    async session({ session, token }) {
      // แนบข้อมูลลง session ตามต้องการ
      if (token?.email) session.user!.email = token.email as string;
      if (token?.name) session.user!.name = token.name as string;
      return session;
    },
  },
};

const handler = NextAuth(authOptions);
export { handler as GET, handler as POST };